/// Example C-compatible callback that accumulates values
#[no_mangle]
pub unsafe extern "C" fn accumulate_callback(
    record: *mut CRecord,
    user_data: *mut c_void,
) -> c_int {
    if record.is_null() || user_data.is_null() {
        return -1;
    }
    let sum = user_data as *mut c_double;
    *sum += (*record).value;
    0
}

