fn main() {
    println!("=== FFI Record Management Demo ===\n");

    // Create individual records
    let record = Record::new(1, "hello_world", 3.14159).unwrap();
    println!("Created: {}", record);

    // Process a batch of records
    let entries = vec![
        (1, "alpha", 100.0),
        (2, "beta", 200.0),
        (3, "gamma", 300.0),
        (4, "delta", 400.0),
    ];

    println!("\nProcessing batch with 1.5x multiplier:");
    let results = process_records_via_ffi(&entries, 1.5).unwrap();
    for (id, name, value) in &results {
        println!("  id={}, name='{}', value={:.2}", id, name, value);
    }

    // Raw struct manipulation
    println!("\nRaw manipulation:");
    let raw_result = manipulate_raw_c_struct(42, "raw_example", 2.71828).unwrap();
    println!("  {}", raw_result);

    // List with callbacks
    println!("\nCallback mechanism:");
    let mut list = RecordList::new().unwrap();
    list.append(Record::new(10, "cb_alpha", 50.0).unwrap())
        .unwrap();
    list.append(Record::new(20, "cb_beta", 75.0).unwrap())
        .unwrap();

    println!("  Before callback - sum: {:.2}", list.sum_values());
    apply_callback_to_list(&list, double_value_callback, ptr::null_mut()).unwrap();
    println!("  After double callback - sum: {:.2}", list.sum_values());

    let mut accumulated: c_double = 0.0;
    let acc_ptr = &mut accumulated as *mut c_double as *mut c_void;
    apply_callback_to_list(&list, accumulate_callback, acc_ptr).unwrap();
    println!("  Accumulated total: {:.2}", accumulated);

    println!("\n=== Demo Complete ===");
}